import React from 'react';
import img1 from './images/download.jpeg';
import img2 from './images/images.jpeg';
import img3 from './images/photo-1437482078695-73f5ca6c96e2.avif';
import './Home.css';

const Home = () => {
  return (
    <div className="home-page">

      {/* Carousel */}
      <div
        id="carouselExampleIndicators"
        className="carousel slide"
        data-bs-ride="carousel"
      >

        {/* Indicators */}
        <div className="carousel-indicators">
          <button type="button" data-bs-target="#carouselExampleIndicators" data-bs-slide-to="0" className="active"></button>
          <button type="button" data-bs-target="#carouselExampleIndicators" data-bs-slide-to="1"></button>
          <button type="button" data-bs-target="#carouselExampleIndicators" data-bs-slide-to="2"></button>
        </div>

        {/* Slides */}
        <div className="carousel-inner">

          <div className="carousel-item active">
            <img src={img1} alt="Colorful Fish" className="carousel-img" />
          </div>

          <div className="carousel-item">
            <img src={img2} alt="Tropical Aquarium" className="carousel-img" />
          </div>

          <div className="carousel-item">
            <img src={img3} alt="Marine Life" className="carousel-img" />
          </div>

        </div>

        {/* Controls */}
        <button className="carousel-control-prev" type="button" data-bs-target="#carouselExampleIndicators" data-bs-slide="prev">
          <span className="carousel-control-prev-icon"></span>
        </button>

        <button className="carousel-control-next" type="button" data-bs-target="#carouselExampleIndicators" data-bs-slide="next">
          <span className="carousel-control-next-icon"></span>
        </button>

      </div>
    </div>
  );
};

export default Home;
